body {
    font-family: Arial, sans-serif;
    font-size: 14px;
    margin: 0;
    padding: 10px;
}

.label-container {
    display: flex;
    flex-wrap: wrap;
    justify-content: space-between;
    gap: 20px;
}

.label {
    width: 100%; /* Adjust if you want 3 per row: use 31% */
    border: 1px solid #000;
    padding: 6px;
    box-sizing: border-box;
    page-break-inside: avoid;
}

table {
    width: 100%;
    border-collapse: collapse;
}

td {
    border: 1px solid #000;
    padding: 3px;
    vertical-align: top;
}

.barcode-img {
    height: 100px; /* Slightly reduced barcode image height */
    display: block;
    margin: 5px auto 0 auto;
}

@media print {
    .label {
        page-break-inside: avoid;
    }
}

