}

table {
    width: 100%;
    border-collapse: collapse;
}

td {
    border: 1px solid #000;
    padding: 4px;
    vertical-align: top;
}

.qr-img, .barcode-img {
    width: 100px;
    height: auto;
    display: block;
    margin: 0 auto;
}

@media print {
    .label {
        page-break-inside: avoid;
    }
}

/* Default: for screen preview — large and scrollable */
.factory-ocr-container {
  font-family: 'Courier New', Courier, monospace;
  font-size: 12px;
  margin: 0;
  padding: 0;
  min-width: 1200px;
}

/* Scrollable preview in browser */
@media screen {
  .print-preview-scroll {
    max-width: 100%;
    overflow-x: auto;
    padding: 10px;
    border: 1px solid #ddd;
    margin: 10px 0;
  }
}

/* Only for Frappe's PDF button (wkhtmltopdf) */
@media print and (max-width: 210mm) {
  .factory-ocr-container {
    font-size: 9.5px !important;
    min-width: auto !important;
    width: 100% !important;
  }
  .main-table {
    table-layout: fixed !important;
    width: 100% !important;
  }
  .main-table th,
  .main-table td {
    padding: 1.5px !important;
    word-wrap: break-word !important;
    white-space: normal !important;
  }
  .header-table td {
    padding: 2px !important;
  }
}

/* Table styles */
.header-title {
  text-align: center;
  font-weight: bold;
  font-size: 14px;
  margin-bottom: 5px;
}

.header-table,
.main-table,
.footer-table {
  border-collapse: collapse;
  width: 100%;
  border: 2px solid black;
}

.header-table td,
.main-table th,
.main-table td,
.footer-table td {
  padding: 3px;
  text-align: center;
}

.main-table th {
  font-weight: bold;
}

.main-table td {
  text-align: right;
}

.main-table td:first-child,
.main-table td:nth-child(2) {
  text-align: left;
}

.totals-row td {
  font-weight: bold;
}

.ship-only-heading {
  text-align: center;
  margin: 10px 0;
  font-weight: bold;
  font-size: 13px;
}

.footer-table td {
  font-size: 12px;
}

.footer-notes {
  font-style: italic;
  vertical-align: top;
  width: 70%;
}

.footer-metrics {
  width: 30%;
  text-align: center;
}

.footer-metrics-title {
  font-weight: bold;
  font-size: 14px;
}

.footer-metrics-value {
  font-size: 20px;
  font-weight: bold;
  margin-top: 5px;
}

.factory-head-sign {
  margin-top: 20px;
  text-align: center;
  font-weight: bold;
  font-size: 13px;
}

